                    handleSuccessfulLogin(
                        userId = supabaseUser.id,
                        email = finalEmail,
                        displayName = finalDisplayName,
                        logDetail = "Connexion via Google"
                    )
                } else {
                    hideLoading()
                    showError("Erreur de connexion avec Google")
                }
            } catch (e: Exception) {
                Log.e("LoginFragment", "Erreur Google→Supabase: ${e.message}", e)
                hideLoading()
