                    else ->
                        "Erreur Google Sign-In: ${e.localizedMessage}"
                }
                showError(errorMsg)
            }
        }
    }

    // ═══════════════════════════════════════════
    // Email/Password Login via Supabase
    // ═══════════════════════════════════════════

    private fun loginWithEmail(email: String, password: String) {
